package ir.tahamohamadi.blog.post.api.admin; import ir.tahamohamadi.blog.post.*; import ir.tahamohamadi.blog.category.*; import ir.tahamohamadi.common.domain.*; import org.springframework.data.domain.*; import org.springframework.stereotype.*; import org.springframework.transaction.annotation.*; import org.springframework.orm.*; import java.time.*; import java.util.*;
@Service @Transactional public class AdminBlogService { final BlogPostRepository posts; final BlogPostTranslationRepository translations; final BlogCategoryRepository categories; public AdminBlogService(BlogPostRepository p,BlogPostTranslationRepository t,BlogCategoryRepository c){posts=p;translations=t;categories=c;} @Transactional(readOnly=true) public Page<AdminBlogSummary> list(Pageable p){return posts.findByDeletedAtIsNullOrderByUpdatedAtDescIdDesc(p).map(x->new AdminBlogSummary(x.getId(),x.getCategory().getId(),x.getStatus().name(),x.getVersion()));} @Transactional(readOnly=true) public AdminBlogResponse get(UUID id){return response(post(id));} public AdminBlogResponse create(AdminBlogCreateRequest r){BlogPost p=posts.save(BlogPost.create(UUID.randomUUID(),category(r.categoryId()),Instant.now())); save(p,r.fa(),r.en());return response(p);} public AdminBlogResponse update(UUID id,AdminBlogUpdateRequest r){BlogPost p=post(id);if(p.getVersion()!=r.version())throw new ObjectOptimisticLockingFailureException(BlogPost.class,id);p.updateCategory(category(r.categoryId()));save(p,r.fa(),r.en());return response(p);} BlogPost post(UUID id){return posts.findById(id).filter(p->p.getDeletedAt()==null).orElseThrow(()->new NoSuchElementException("Blog post not found"));} BlogCategory category(UUID id){return categories.findById(id).filter(c->c.getDeletedAt()==null&&c.isActive()).orElseThrow(()->new NoSuchElementException("Category not found"));} void save(BlogPost p,BlogTranslationRequest fa,BlogTranslationRequest en){save(p,LanguageCode.fa,fa);save(p,LanguageCode.en,en);} void save(BlogPost p,LanguageCode l,BlogTranslationRequest r){translations.findByBlogPostIdAndDeletedAtIsNull(p.getId()).stream().filter(t->t.getLanguageCode()==l).findFirst().ifPresentOrElse(t->t.update(r.title(),r.slug(),r.excerpt(),r.bodyMarkdown(),r.seoTitle(),r.seoDescription()),()->translations.save(BlogPostTranslation.create(UUID.randomUUID(),p,l,r.title(),r.slug(),r.bodyMarkdown(),Instant.now())));} AdminBlogResponse response(BlogPost p){var ts=translations.findByBlogPostIdAndDeletedAtIsNull(p.getId());return new AdminBlogResponse(p.getId(),p.getCategory().getId(),p.getStatus().name(),dto(ts,LanguageCode.fa),dto(ts,LanguageCode.en),p.getVersion());} BlogTranslationRequest dto(List<BlogPostTranslation> ts,LanguageCode l){var t=ts.stream().filter(x->x.getLanguageCode()==l).findFirst().orElseThrow();return new BlogTranslationRequest(t.getTitle(),t.getSlug(),t.getExcerpt(),t.getBodyMarkdown(),t.getSeoTitle(),t.getSeoDescription());}}
